use tokio_postgres::{Client, NoData, Error};
use std::env;
use tokio;

pub struct User {
    pub id: i32,
    pub name: String,
    pub email: String,
}

pub async fn search_users_by_email(
    client: &Client,
    email_search_term: &str,
) -> Result<Vec<User>, Error> {
    let query = "SELECT id, name, email FROM users WHERE email = $1";
    let rows = client.query(query, &[&email_search_term]).await?;

    let users: Vec<User> = rows
        .into_iter()
        .map(|row| User {
            id: row.get("id"),
            name: row.get("name"),
            email: row.get("email"),
        })
        .collect();

    Ok(users)
}

